import os
import torch
import requests

def download_model(url, model_name):
    response = requests.get(url)
    if response.status_code == 200:
        with open(model_name, 'wb') as f:
            f.write(response.content)
        print(f"{model_name} downloaded successfully.")
    else:
        print(f"Failed to download {model_name}.")

def load_model(model_name):
    model = torch.load(model_name)
    print(f"{model_name} loaded successfully.")
    return model

def fine_tune_model(model, train_loader, num_epochs=5, learning_rate=0.001):
    optimizer = torch.optim.Adam(model.parameters(), lr=learning_rate)
    criterion = torch.nn.CrossEntropyLoss()

    for epoch in range(num_epochs):
        for inputs, labels in train_loader:
            optimizer.zero_grad()
            outputs = model(inputs)
            loss = criterion(outputs, labels)
            loss.backward()
            optimizer.step()
        print(f"Epoch {epoch+1}/{num_epochs} completed.")

# Example usage
model_url = 'http://example.com/path/to/pretrained/model.pth'
model_name = 'model.pth'

download_model(model_url, model_name)
model = load_model(model_name)

# Assume train_loader is defined
fine_tune_model(model, train_loader)